@pytest.mark.asyncio
async def test_developer_message() -> None:
    """Chat request that includes a developer role message alongside user messages."""
    request = {
        "messages": [
            {
                "content": "You are a coding assistant. Always respond with concise code examples.",
                "role": "developer",
            },
            {"content": "How do I reverse a string in Python?", "role": "user"},
        ],
        "model": "gpt-4",
    }
    client = create_client(
        api_key="test-key",
        base_url=os.environ["MOCK_SERVER_URL"] + "/fixtures/developer_message",
    )
    result = await client.chat(request)
    assert len(result.choices) == 1  # noqa: S101
    assert result.choices[0].message.content.strip() == "s[::-1]"  # noqa: S101
    assert result.choices[0].finish_reason.strip() == "stop"  # noqa: S101


