@pytest.mark.asyncio
async def test_parallel_tool_calls() -> None:
    """Chat request that results in parallel tool calls in the response."""
    request = {
        "messages": [
            {"content": "What is the weather in NYC and London?", "role": "user"}
        ],
        "model": "gpt-4",
        "parallel_tool_calls": True,
        "tools": [
            {
                "function": {
                    "description": "Get the current weather for a given location",
                    "name": "get_weather",
                    "parameters": {
                        "properties": {
                            "location": {
                                "description": "The city name",
                                "type": "string",
                            }
                        },
                        "required": ["location"],
                        "type": "object",
                    },
                },
                "type": "function",
            }
        ],
    }
    client = create_client(
        api_key="test-key",
        base_url=os.environ["MOCK_SERVER_URL"] + "/fixtures/parallel_tool_calls",
    )
    result = await client.chat(request)
    assert len(result.choices) == 1  # noqa: S101
    assert result.choices[0].message.tool_calls  # noqa: S101
    assert len(result.choices[0].message.tool_calls) == 2  # noqa: S101
    assert result.choices[0].finish_reason.strip() == "tool_calls"  # noqa: S101


